use actix_files::NamedFile;
use actix_web::{web, App, HttpServer, Responder};
use std::path::Path;

async fn serve_file(path: web::Path<String>) -> impl Responder {
    let filename = path.into_inner();
    let file_path = format!("./uploads/{}", filename);
    
    match NamedFile::open(file_path).await {
        Ok(file) => file,
        Err(_) => actix_web::HttpResponse::NotFound().body("File not found"),
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .route("/files/{filename}", web::get().to(serve_file))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}